import React from 'react';

const PortfolioGlobalPage = () => {
  return (
    <div className="p-6 font-body">
      <h1 className="text-2xl font-display font-bold text-white mb-2">Global Portfolio</h1>
      <p className="text-slate-400">Firm-wide assets under management and holdings.</p>

      <div className="mt-8 bg-surface-800 border border-surface-600 rounded-xl p-6 flex flex-col items-center justify-center text-center h-64">
        <div className="text-4xl mb-4">📊</div>
        <h3 className="text-white font-medium mb-2">Aggregated View</h3>
        <p className="text-slate-500 text-sm max-w-sm">This page provides a macro view of all client assets, sector allocations, and overall firm performance.</p>
      </div>
    </div>
  );
};

export default PortfolioGlobalPage;
